import{_ as s,o as e,c as p,a0 as i}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"GNU Radio 3.8.0.0安装","description":"","frontmatter":{"title":"GNU Radio 3.8.0.0安装","date":"2019-09-01T21:14:35.000Z","category":"Radio","tags":["软件无线电"]},"headers":[],"relativePath":"posts/gnu-radio-3800-an-zhuang.md","filePath":"posts/gnu-radio-3800-an-zhuang.md","lastUpdated":1783006593000}'),t={name:"posts/gnu-radio-3800-an-zhuang.md"};function n(o,a,l,d,c,r){return e(),p("div",null,[...a[0]||(a[0]=[i(`<h1 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h1><p>GNU Radio 3.8.0.0正式版已经发布很久了，git上最新版本都已经3.9了，但在安装3.8时候遇到过不少问题，这里就简单介绍下3.8版本安装流程。</p><h1 id="基础环境" tabindex="-1">基础环境 <a class="header-anchor" href="#基础环境" aria-label="Permalink to &quot;基础环境&quot;">​</a></h1><p>系统依旧是Ubuntu 18.04 LTS，可以看<a href="http://blog.white-alone.com/Ubuntu%2018.04%E9%85%8D%E7%BD%AEGNURadio%E5%9F%BA%E7%A1%80%E7%8E%AF%E5%A2%83/" target="_blank" rel="noreferrer">《Ubuntu 18.04配置GNURadio基础环境》</a></p><p>安装依赖：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>apt-get install python-pip python3-pip proxychains4  libproxychains4 git cmake g++ libboost-all-dev libgmp-dev swig python3-numpy python3-mako python3-sphinx python3-lxml doxygen libfftw3-dev libcomedi-dev libsdl1.2-dev libgsl-dev libqwt-qt5-dev libqt5opengl5-dev python3-pyqt5 liblog4cpp5-dev libzmq3-dev python3-yaml python3-click python3-click-plugins</span></span></code></pre></div><p>如果是intel集显</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>apt-get install beignet-dev</span></span></code></pre></div><p>如果是nvidia独显</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>apt-get install nvidia-opencl-dev</span></span></code></pre></div><h1 id="安装gnu-radio" tabindex="-1">安装GNU Radio <a class="header-anchor" href="#安装gnu-radio" aria-label="Permalink to &quot;安装GNU Radio&quot;">​</a></h1><p>安装pybombs</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git clone https://github.com/gnuradio/pybombs.git</span></span>
<span class="line"><span>cd pybombs</span></span>
<span class="line"><span>python setup.py install</span></span>
<span class="line"><span></span></span>
<span class="line"><span>pybombs recipes add gr-recipes git+https://github.com/gnuradio/gr-recipes.git  </span></span>
<span class="line"><span>pybombs recipes add gr-etcetera git+https://github.com/gnuradio/gr-etcetera.git</span></span></code></pre></div><p>配置安装路径</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pybombs prefix init /usr/local</span></span></code></pre></div><p>需要修改一下默认lwr文件</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vi /root/.pybombs/recipes/gr-recipes/gnuradio.lwr</span></span></code></pre></div><p>将<code>gitbranch: maint-3.7</code>改为<code>gitbranch: maint-3.8</code></p><p>之后就可以安装GNU Radio了</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pybombs install gnuradio</span></span></code></pre></div><p>如果要支持airspy、hackrf、rtl-sdr、bladerf等等，需要安装<code>gr-osmosdr</code>，但官方还没有对3.8做适配，还需要修改2个lwr文件，否则安装会报错。</p><p>修改gr-osmosdr.lwr</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vi /root/.pybombs/recipes/gr-recipes/gr-osmosdr.lwr</span></span></code></pre></div><p>将git地址和版本改为：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gitbranch: gr3.8</span></span>
<span class="line"><span>source: https://github.com/igorauad/gr-osmosdr.git</span></span></code></pre></div><p>以及gr-iqbal.lwr</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vi /root/.pybombs/recipes/gr-recipes/gr-iqbal.lwr</span></span></code></pre></div><p>同样修改git地址和版本</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gitbranch: gr3.8</span></span>
<span class="line"><span>source: https://github.com/mvaenskae/gr-iqbal.git</span></span></code></pre></div><p>安装gqrx，默认包含gr-osmosdr airspy hackrf soapysdr bladeRF gr-iqbal libosmo-dsp osmo-sdr rtl-sdr，但当前兼容有问题，安装会报错</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pybombs install gqrx</span></span></code></pre></div><p>如果使用limesdr，还需要修改<code>gr-limesdr</code>，当前只有RX可用</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vi /root/.pybombs/recipes/gr-recipes/gr-limesdr.lwr</span></span></code></pre></div><p>将<code>gitbranch: master</code>改为<code>gitbranch: develop</code>就可以了</p><p>如果使用plutoSDR，需要修改<code>gr-iio</code>，但当前还无法使用</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vi /root/.pybombs/recipes/gr-recipes/gr-iio.lwr</span></span></code></pre></div><p>将<code>gitbranch: tags/v0.3</code>改为<code>gitbranch: upgrade-3.8</code></p><p>安装其他组件，<code>gr-fosphor</code>当前还有问题</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pybombs install airspy airspyhf hackrf soapysdr bladeRF rtl-sdr libiio  limesuite soapysdr gr-limesdr gr-iio gr-fosphor gnss-sdr dump1090</span></span></code></pre></div><p>安装完就可以<code>gnuradio-companion </code>命令打开GNU Radio 3.8.0.0了。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/GNU_Radio_3.8.0.0%E5%AE%89%E8%A3%85/1591023848263.png" alt=""></p><p>新版本的GNU Radio好看很多，抛弃了WX只有QT，代码除了py还有c++，改进了很多，但大体上功能差不多，有兴趣的童鞋可以安装试试。</p>`,42)])])}const b=s(t,[["render",n]]);export{h as __pageData,b as default};
